 1	import { Button, Popper } from '@patternfly/react-core';
 2	import { CogIcon } from '@patternfly/react-icons';
 3	import * as React from 'react';
 4	import { useTranslation } from 'react-i18next';
 5	import { FlowScope } from '../../model/flow-query';
 6	import { ScopeConfigDef } from '../../model/scope';
 7	import { useOutsideClickEvent } from '../../utils/outside-hook';
 8	import './overview-display-dropdown.css';
 9	import { OverviewDisplayOptions } from './overview-display-options';
10	import { TruncateLength } from './truncate-dropdown';
11	
12	export type Size = 's' | 'm' | 'l';
13	
14	export interface OverviewDisplayDropdownProps {
15	  metricScope: FlowScope;
16	  setMetricScope: (s: FlowScope) => void;
17	  truncateLength: TruncateLength;
18	  setTruncateLength: (v: TruncateLength) => void;
19	  focus: boolean;
20	  setFocus: (v: boolean) => void;
21	  scopes: ScopeConfigDef[];
22	}
23	
24	export const OverviewDisplayDropdown: React.FC<OverviewDisplayDropdownProps> = ({
25	  metricScope,
26	  setMetricScope,
27	  truncateLength,
28	  setTruncateLength,
29	  focus,
30	  setFocus,
31	  scopes
32	}) => {
33	  const { t } = useTranslation('plugin__netobserv-plugin');
34	  const containerRef = React.useRef<HTMLDivElement>(null);
35	  const triggerRef = React.useRef<HTMLButtonElement>(null);
36	  const popperRef = React.useRef<HTMLDivElement>(null);
37	  const [isOpen, setOpen] = React.useState<boolean>(false);
38	
39	  const ref = useOutsideClickEvent(() => setOpen(false));
40	
41	  const trigger = React.useCallback(() => {
42	    return (
43	      <Button
44	        ref={triggerRef}
45	        variant="link"
46	        icon={<CogIcon />}
47	        onClick={() => setOpen(!isOpen)}
48	        data-test="display-dropdown-button"
49	      >
50	        {t('Display options')}
51	      </Button>
52	    );
53	  }, [isOpen, t]);
54	
55	  const popper = React.useCallback(() => {
56	    return (
57	      <div id="overview-display-popper" ref={popperRef} className="pf-v6-c-menu" role="dialog">
58	        <OverviewDisplayOptions
59	          metricScope={metricScope}
60	          setMetricScope={setMetricScope}
61	          truncateLength={truncateLength}
62	          setTruncateLength={setTruncateLength}
63	          focus={focus}
64	          setFocus={setFocus}
65	          scopes={scopes}
66	        />
67	      </div>
68	    );
69	  }, [metricScope, setMetricScope, truncateLength, setTruncateLength, focus, setFocus, scopes]);
70	
71	  return (
72	    <div id="display-dropdown-container" data-test="display-dropdown-container" ref={ref}>
73	      <div ref={containerRef}>
74	        <Popper
75	          trigger={trigger()}
76	          triggerRef={triggerRef}
77	          popper={popper()}
78	          popperRef={popperRef}
79	          isVisible={isOpen}
80	          enableFlip={true}
81	          appendTo={containerRef.current || undefined}
82	        />
83	      </div>
84	    </div>
85	  );
86	};
87	
88	export default OverviewDisplayDropdown;

